mapper.select:
select designer_id, user_id, name, phone, phone_hash, company, group_id, discount, status, download_count
from bh_designer
where designer_id = #{designerId}

mapper.insert:
insert into bh_designer (
    user_id, name, phone, phone_hash, company, group_id, discount, status,
    download_count, create_by, create_time, update_by, update_time
) values (
    #{userId}, #{name}, #{phone}, #{phoneHash}, #{company}, #{groupId}, #{discount}, #{status},
    #{downloadCount}, #{createBy}, #{createTime}, #{updateBy}, #{updateTime}
)

mapper.update:
update bh_designer
name = #{name}, phone = #{phone}, phone_hash = #{phoneHash}, company = #{company}, group_id = #{groupId}, discount = #{discount}, status = #{status}, update_by = #{updateBy}, update_time = #{updateTime}
where designer_id = #{designerId}
